(10, 38, NULL, 40, 50, 30, 20, 40, NULL, NULL, 'نقد و بانک,انبار,فروش,مالی,حقوق', NULL, 'حسابدار انبار، حقوق و دستمزد، تهیه و ارسال لیست بیمه و مالیات حقوق، خزانه درحد کنترل حسابها و ثبت های مربوطه.\nدرتهیه گزازشات مالیاتی مثل ارزش افزوده و فصلی اشنایی دارم ولی مستقیم کارنکردم.', NULL, 1, 0, NULL, '', '2021-10-12 10:50:00', '2025-07-29 06:13:03'),
(11, 37, NULL, 60, 30, NULL, 50, 70, NULL, NULL, 'نقد و بانک', NULL, NULL, NULL, 1, 0, NULL, NULL, '2021-10-12 10:50:01', '2021-10-12 10:50:01'),
(12, 40, NULL, 8, 9, NULL, 8, 7, NULL, NULL, 'فروش', NULL, '۱-طیبه عزیزیان\n۲-متولد ۱۳۶۷/۰۶/۰۱\n۳-لیسانس مدیریت بازرگانی\n۴-متاهل ودارای یک فرزند ۵ساله-\n۵- ۳سال و۶ماه سابقه کاری \n     به ترتیب از اولین کار\n۶ماه کار در شرکت پخش مواد غذایی شبستان به عنوان اپراتور فروش و ثبت فاکتور کار با نرم افزار ویژن\n۲سال و۶ماه کار در شرکت پخش روغن لادن شرکت طلوع پخش آفتاب به عنوان اپراتور فروش و ثبت فاکتور و کارهای اداری کار با نرم افزار سلز باز \n۶ماه کار در دفتر کاشی وسرامیک عامل به عنوان کمک حسابدار کار با نرم افزار سازه حساب و ثبت حواله حسابداری ثبت فاکتور و... آشنایی با نرم افزار محک ثبت اسناد حسابداری ثبت فاکتور\n۶-سه سال سابقه بیمه تامین اجتماعی\n۷-آدرس گاز مسلم شمالی\n۸-شماره همراه ۰۹۱۵۲۴۵۱۷۴۲', NULL, 1, 1, NULL, NULL, '2021-10-12 11:44:53', '2021-10-12 11:44:53'),
(13, 41, NULL, 1, 1, NULL, 1, 1, NULL, NULL, 'مالی', NULL, 'تا به حال فعالیت مالی نداشتم دانشجو هستم و فقط به صورت تئوری بوده', NULL, 1, 0, NULL, NULL, '2021-10-12 12:15:12', '2021-10-12 12:15:12'),
